namespace QAHub.Api.Domain.Execution;public sealed class TestRunAttempt{private TestRunAttempt(){}public TestRunAttempt(Guid cycleItemId,int attempt,ExecutionResult result,string actualResult,string evidence,string reason,string actor){if(result is ExecutionResult.Failed or ExecutionResult.Blocked&&(string.IsNullOrWhiteSpace(actualResult)||string.IsNullOrWhiteSpace(evidence)||string.IsNullOrWhiteSpace(reason)))throw new ArgumentException("Failed/Blocked require actual result, evidence and reason.");if(result==ExecutionResult.Skipped&&string.IsNullOrWhiteSpace(reason))throw new ArgumentException("Skipped requires reason.");Id=Guid.NewGuid();TestCycleItemId=cycleItemId;AttemptNumber=attempt;Result=result;ActualResult=actualResult.Trim();Evidence=evidence.Trim();Reason=reason.Trim();ExecutedBy=actor;ExecutedAtUtc=DateTimeOffset.UtcNow;}public Guid Id{get;private set;}public Guid TestCycleItemId{get;private set;}public int AttemptNumber{get;private set;}public ExecutionResult Result{get;private set;}public string ActualResult{get;private set;}=string.Empty;public string Evidence{get;private set;}=string.Empty;public string Reason{get;private set;}=string.Empty;public string ExecutedBy{get;private set;}=string.Empty;public DateTimeOffset ExecutedAtUtc{get;private set;}}
